B.aaE=new A.f(B.w,"AMM neden standart bir dil kullan\u0131r","Aircraft Maintenance Manual (AMM), teknik prosed\xfcrlerin evrensel olarak anla\u015f\u0131lmas\u0131n\u0131 sa\u011flamak i\xe7in **ASD-STE100 (Simplified Technical English)** standard\u0131n\u0131 kullan\u0131r.\n\nBu standart: k\u0131sa c\xfcmleler, aktif fiil kullan\u0131m\u0131, belirsiz olmayan teknik terimler ve onayl\u0131 kelime listesi i\xe7erir. AMM'yi do\u011fru okumak; g\xfcvenli bak\u0131m, EASA/FAA uyumlulu\u011fu ve kaza \xf6nleme a\xe7\u0131s\u0131ndan kritiktir.",null,null,null,null,null,null,null)
B.a8s=new A.f(B.t,"\ud83d\udd27 AMM Temel Yap\u0131lar\u0131",'**Zorunluluk dili (Modal verbs):**\n\u2022 "must" \u2014 zorunlu eylem (EASA/FAA \u015fart\u0131)\n\u2022 "shall" \u2014 resmi zorunluluk\n\u2022 "should" \u2014 tavsiye\n\u2022 "may" \u2014 izin verilen eylem\n\n**Prosed\xfcr fiilleri:**\n\u2022 inspect \u2014 g\xf6rsel kontrol yap\n\u2022 remove/install \u2014 s\xf6k\xfcp/takma\n\u2022 torque to \u2014 belirtilen tork de\u011ferine s\u0131k\n\u2022 apply \u2014 uygula (torque, lubricant, sealant)\n\u2022 verify \u2014 do\u011frula\n\u2022 record \u2014 kay\u0131t al\n\n**Uyar\u0131 seviyeleri:**\n\u2022 WARNING \u2014 ki\u015fisel yaralanma veya \xf6l\xfcm riski\n\u2022 CAUTION \u2014 ekipman hasar\u0131 riski\n\u2022 NOTE \u2014 prosed\xfcr bilgisi',null,null,null,null,null,null,null)
