B.a7U=new A.f(B.w,"Gelecek Zaman nas\u0131l tan\u0131n\u0131r?",'**Will** ve **be going to** gelecek zaman\u0131 ifade eder. Belirli anahtar kelimeler bu yap\u0131n\u0131n ipucudur.\n\n**\xd6nemli not:** "Before long" \u2192 \xe7ok ge\xe7meden (gelecek) / "Long before" \u2192 \xe7ok \xf6nceden (ge\xe7mi\u015f)',null,null,null,null,null,null,null)
B.a5X=new A.f(B.t,"Future Simple Anahtar Kelimeleri",'**Gelecek zaman belirte\xe7leri:**\n\u2022 tomorrow, later today\n\u2022 next week / month / year\n\u2022 in + gelecek zaman \u2192 "in 2050", "in two hours"\n\u2022 within + s\xfcre \u2192 "within a month"\n\u2022 before long \u2192 "\xe7ok ge\xe7meden"\n\u2022 soon, shortly\n\n**Will kullan\u0131m\u0131:** anl\u0131k karar, tahmin, s\xf6z\n**Going to kullan\u0131m\u0131:** \xf6nceden planlanm\u0131\u015f eylem, kan\u0131ta dayal\u0131 tahmin\n\n\u26a0\ufe0f "Before long" = soon (GELECEK)\n\u26a0\ufe0f "Long before" = much earlier (GE\xc7M\u0130\u015e)',null,null,null,null,null,null,null)
