B.a83=new A.f(B.t,"Muayene T\xfcrleri","**General Visual Inspection (GVI):**\n\u2014 Geni\u015f alanda, eri\u015fim gerekmeksizin yap\u0131lan genel g\xf6rsel muayene\n\u2014 Hasar\u0131, ar\u0131zay\u0131, d\xfczensizli\u011fi tespit etmek i\xe7in\n\n**Detailed Inspection (DET):**\n\u2014 Yak\u0131n mesafeden, genellikle ayd\u0131nlatma ve b\xfcy\xfctme yard\u0131m\u0131yla\n\u2014 Belirli bir alana odaklan\u0131r\n\n**Special Detailed Inspection (SDI):**\n\u2014 NDT (Non-Destructive Testing) teknikleri i\xe7erir\n\u2014 Borescope, eddy current, ultrasonic, X-ray\n\n**Operational Check:**\n\u2014 Sistemin tasar\u0131m fonksiyonunu ger\xe7ekle\u015ftirip ger\xe7ekle\u015ftirmedi\u011fini do\u011frular\n\n**Functional Check:**\n\u2014 Belirli fonksiyonun quantitative (say\u0131sal) olarak do\u011frulanmas\u0131",null,null,null,null,null,null,null)
