B.a5v=new A.f(B.w,"Bu \xfc\xe7 modal aras\u0131ndaki fark",'**Can** \u2192 yetenek veya izin (g\xfcnl\xfck dil)\n**Could** \u2192 ge\xe7mi\u015fte yetenek, kibar rica, olas\u0131l\u0131k\n**May** \u2192 resmi izin, olas\u0131l\u0131k\n\nHavac\u0131l\u0131kta ATC konu\u015fmalar\u0131nda "May we proceed?" ve "You may descend" \xe7ok s\u0131k kullan\u0131l\u0131r.',null,null,null,null,null,null,null)
