B.a6m=new A.f(B.w,"ATC ifade kal\u0131plar\u0131 standartt\u0131r","Hava Trafik Kontrol ileti\u015fimleri ICAO standart ifade kal\u0131plar\u0131n\u0131 izler. Bo\u015fluk doldurma sorular\u0131, klirens, talimat ve tekrar (readback) ifadelerinde kullan\u0131lan **tam kelimeleri** bilip bilmedi\u011finizi s\u0131nar.\n\nAnahtar, her ifade t\xfcr\xfcn\xfcn **yap\u0131s\u0131n\u0131** anlamakt\u0131r; b\xf6ylece her ifadeyi ezberlemenize gerek kalmadan eksik kelimeyi bulabilirsiniz.",null,null,null,null,null,null,null)
B.aaK=new A.f(B.t,"\ud83d\udeeb Klirans Yap\u0131s\u0131",'Standart bir ATC klirans\u0131 \u015fu kal\u0131b\u0131 izler:\n\n**U\xe7ak kimli\u011fi** + klirans limiti + rota + irtifa + h\u0131z + squawk\n\n\xd6rnek: "THY123, **cleared to** \u0130stanbul, via KEMER, **climb and maintain** FL350, squawk 4521."\n\nTemel fiiller: **cleared**, **maintain**, **climb**, **descend**, **turn**, **contact**, **report**',null,null,null,null,null,null,null)
B.a4u=new A.f(B.t,"\ud83d\udcfb Tekrar Etme Kurallar\u0131",'Pilotlar a\u015fa\u011f\u0131dakilerin hepsini **tekrar etmek** (**read back**) zorundad\u0131r:\n\u2022 Kullan\u0131lan pist\n\u2022 Altimetre ayarlar\u0131\n\u2022 \u0130rtifa/u\xe7u\u015f seviyesi\n\u2022 Y\xf6n talimatlar\u0131\n\u2022 H\u0131z talimatlar\u0131\n\u2022 Frekans de\u011fi\u015fiklikleri\n\u2022 Transponder kodlar\u0131\n\u2022 Taksi talimatlar\u0131 (kontroll\xfc havalimanlar\u0131nda)\n\n**Standart ifade:** "Cleared to FL350, THY123." (tekrarda \xe7a\u011fr\u0131 kodu sonda s\xf6ylenir)',null,null,null,null,null,null,null)
B.WO=new A.r(u.G,"THY123, al\xe7al ve u\xe7u\u015f seviyesi 150'yi koru.","descend and maintain")
