B.a2B=new A.f(B.w,"Korozyon neden kritiktir?","Korozyon, hava arac\u0131 yap\u0131sal b\xfct\xfcnl\xfc\u011f\xfcn\xfc tehdit eden en \xf6nemli sorunlardan biridir. AMT'nin farkl\u0131 korozyon t\xfcrlerini tan\u0131mlayabilmesi ve raporunu do\u011fru yazabilmesi zorunludur.",null,null,null,null,null,null,null)
B.a6j=new A.f(B.t,"Korozyon Terminolojisi",'**T\xfcrler:**\n\u2022 Surface corrosion \u2014 y\xfczey korozyonu (oksitlenme)\n\u2022 Pitting corrosion \u2014 \xe7ukur/nokta korozyonu\n\u2022 Intergranular corrosion \u2014 taneler aras\u0131 korozyon\n\u2022 Galvanic corrosion \u2014 farkl\u0131 metaller temas\u0131ndan olu\u015fan\n\u2022 Stress corrosion cracking \u2014 gerilim + korozyon birlikteli\u011fi\n\u2022 Filiform corrosion \u2014 boya alt\u0131 ince ipliksi korozyon\n\n**Derecelendirme (severity):**\n\u2022 Level 1 \u2014 y\xfczeysel, temizlenebilir\n\u2022 Level 2 \u2014 derinlemesine, onar\u0131m gerektirir\n\u2022 Level 3 \u2014 yap\u0131sal etkisi var, par\xe7a de\u011fi\u015fimi gerekebilir\n\n**Rapor ifadesi:**\n"Corrosion found on [component]. Type: [pitting/surface]. Extent: [area in cm\xb2]. Depth: [mm]. Level: [1/2/3]. Action taken: [clean and treat / blend / replace]."',null,null,null,null,null,null,null)
