B.a2K=new A.f(B.w,"Modern aviyonik sistemler","Modern u\xe7aklarda aviyonik sistemler kendi kendini test edebilen (BITE \u2014 Built-In Test Equipment) \xf6zelli\u011fe sahiptir. AMT'nin bu sistemlerin \xe7\u0131kt\u0131lar\u0131n\u0131 anlayabilmesi ve ar\u0131za giderimini do\u011fru belgelemesi gerekir.",null,null,null,null,null,null,null)
B.a9D=new A.f(B.t,"Aviyonik Terminoloji",'**BITE** \u2014 Built-In Test Equipment: sistem i\xe7indeki otomatik test fonksiyonu\n**Fault code / fault message** \u2014 ar\u0131za kodu veya mesaj\u0131\n**LRU** \u2014 Line Replaceable Unit: sahada de\u011fi\u015ftirilebilen en k\xfc\xe7\xfck birim\n**Intermittent fault** \u2014 aral\u0131kl\u0131 ar\u0131za (s\xfcrekli tekrarlamayan)\n**Confirmed fault** \u2014 do\u011frulanm\u0131\u015f ar\u0131za (BITE s\xfcrekli kay\u0131t ediyor)\n**NFF** \u2014 No Fault Found: LRU de\u011fi\u015ftirildi fakat ar\u0131za bulunamad\u0131\n**ACMS** \u2014 Aircraft Condition Monitoring System\n**DFDR** \u2014 Digital Flight Data Recorder verisi\n\nTroubleshooting ifadeleri:\n"Access BITE menu on MCDU and retrieve active faults."\n"Fault confirmed: [LRU name] faulty. Replace LRU in accordance with AMM."\n"No fault found after LRU replacement. Monitor for recurrence."',null,null,null,null,null,null,null)
