B.jp=new A.al("std_12","Ge\xe7mi\u015fte S\xfcregelen Eylem","Past Continuous \u2014 ge\xe7mi\u015fte devam eden eylem","grammar","\ud83d\udd04",B.akV,B.aB)
B.a4d=new A.f(B.w,"NOTAM nedir?","Bir **NOTAM** (Notice to Air Missions \u2014 Havac\u0131l\u0131k Operasyonlar\u0131na Bildirim), u\xe7u\u015f operasyonlar\u0131yla ilgili personele da\u011f\u0131t\u0131lan resmi bir bildirimdir. Herhangi bir havac\u0131l\u0131k tesisi, hizmet, prosed\xfcr veya tehlike hakk\u0131nda olu\u015fturma, durum veya de\u011fi\u015fiklik bilgisi i\xe7erir.\n\nOkuma anlama sorular\u0131 \xe7o\u011funlukla NOTAM tarz\u0131 metinler ya da bak\u0131m/muayene belgeleri kullan\u0131r.",null,null,null,null,null,null,null)
B.a7K=new A.f(B.t,"\ud83d\udccb NOTAM Yap\u0131s\u0131",'Bir NOTAM \u015funlar\u0131 i\xe7erir:\n**Q)** \u2014 Konu/durum/trafik kodlar\u0131\n**A)** \u2014 Konum (ICAO kodu)\n**B)** \u2014 Ba\u015flang\u0131\xe7 tarihi/saati\n**C)** \u2014 Biti\u015f tarihi/saati\n**E)** \u2014 Tam metin a\xe7\u0131klamas\u0131\n\n\xd6rnek yap\u0131:\n"A0123/24 NOTAMN\nQ) LTAA/QMRLC/IV/NBO/A/000/999/4059N02858E005\n**A) LTBA B) 2401150600 C) 2401152359**\n**E) RWY 36L/18R CLOSED FOR MAINTENANCE"**',null,null,null,null,null,null,null)
B.a4C=new A.f(B.t,"\ud83d\udd0d Okuma Anlama Stratejisi",'Herhangi bir havac\u0131l\u0131k metni i\xe7in (NOTAM, rapor, k\u0131lavuz al\u0131nt\u0131s\u0131):\n1. **\xd6nce tara** \u2014 belge t\xfcr\xfcn\xfc ve konuyu belirle\n2. **Soruyu oku, sonra metni yeniden oku** \u2014 neye bakaca\u011f\u0131n\u0131 bil\n3. **Anahtar ger\xe7ekleri bul** \u2014 tarihler, yerler, k\u0131s\u0131tlamalar, gereklilikler\n4. **Olumsuzlamalara dikkat et** \u2014 "not", "except", "unless" anlam\u0131 tamamen de\u011fi\u015ftirir\n5. **Varsay\u0131mdan ka\xe7\u0131n** \u2014 yaln\u0131zca verilen metinden yan\u0131t ver',null,null,null,null,null,null,null)
B.Un=new A.r("Detailed Inspection (DI) is an intensive examination of a specific item to detect damage, failure or irregularity.","Detayl\u0131 Muayene (DI), hasar, ar\u0131za veya d\xfczensizlikleri tespit etmek i\xe7in belirli bir \xfcr\xfcn\xfcn yo\u011fun incelemesidir.","detect damage, failure or irregularity")
B.UY=new A.r("Available lighting is normally supplemented with a direct source of good lighting at an intensity deemed appropriate.","Mevcut ayd\u0131nlatma normalde uygun g\xf6r\xfclen yo\u011funlukta iyi bir ayd\u0131nlatma kayna\u011f\u0131yla desteklenir.","supplemented")
B.agm=s([B.Un,B.UY],t.l)
B.a5j=new A.f(B.A,"\xd6rnek Pasaj",null,B.agm,null,null,null,null,null,null)
B.a9H=new A.f(B.al,"\u2708\ufe0f Okuma \u0130pu\xe7lar\u0131",'Soru t\xfcrlerine dikkat et:\n\u2022 **"Ana ama\xe7 nedir?"** \u2192 a\xe7\u0131l\u0131\u015f tan\u0131m c\xfcmlesini ara\n\u2022 **"Hangisi GEREKL\u0130 DE\u011e\u0130LD\u0130R?"** \u2192 listeyi bul ve eksik/d\u0131\u015flanan \xf6geyi belirle\n\u2022 **"Metne g\xf6re..."** \u2192 yan\u0131t a\xe7\u0131k\xe7a belirtilmi\u015f olmal\u0131, \xe7\u0131kar\u0131m yap\u0131lmamal\u0131\n\u2022 **"X neyi inceler?"** \u2192 anahtar fiilin do\u011frudan nesnesini bul',null,null,null,null,null,null,null)
B.ahl=s(["To replace damaged components","To detect damage, failure, or irregularity","To clean the surface of the aircraft","To troubleshoot system malfunctions"],t.s)
B.aEP=new A.j(-70,B.a_,601,"What is the main purpose of a Detailed Inspection?",B.ahl,1,B.m,null,null,null)
B.ap3=s(["Direct source of good lighting","Inspection aids such as mirrors","Complete disassembly of the aircraft","Surface cleaning"],t.s)
B.aDo=new A.j(-71,B.a_,602,"Which of the following is NOT necessarily required for a Detailed Inspection?",B.ap3,2,B.n,null,null,null)
B.asL=s(["An entire aircraft at once","The aircraft's documentation","A specific item, installation, or assembly","Only the exterior of the aircraft"],t.s)
B.aBk=new A.j(-72,B.a_,603,"What does a Detailed Inspection examine?",B.asL,2,B.m,null,null,null)
B.agW=s([B.aEP,B.aDo,B.aBk],t.C)
B.a3k=new A.f(B.v,"Pratik Sorular",'Read the following passage, then answer the questions.\n\n"Detailed Inspection (DI) is an intensive examination of a specific item, installation, or assembly to detect damage, failure or irregularity. Available lighting is normally supplemented with a direct source of good lighting at an intensity deemed appropriate. Inspection aids such as mirrors, magnifying lenses etc. may be necessary. Surface cleaning and elaborate access procedures may be required."',null,null,B.agW,null,null,null,null)
B.aiq=s([B.a4d,B.a7K,B.a4C,B.a5j,B.a9H,B.a3k],t.q)
B.jl=new A.al("reading_1","NOTAM Okuma","Havac\u0131l\u0131k Bildirimlerini Anlama","reading","\ud83d\udcc4",B.aiq,B.C)
B.aaj=new A.f(B.w,"Past Perfect nas\u0131l tan\u0131n\u0131r?","Past Perfect (had + V3), ge\xe7mi\u015fteki iki olaydan **\xf6nce ger\xe7ekle\u015feni** anlat\u0131r. Havac\u0131l\u0131k kaza soru\u015fturmalar\u0131nda olaylar\u0131n s\u0131ras\u0131n\u0131 belirtmek i\xe7in kritiktir.\n\n**Not:** Past Perfect her zaman zorunlu de\u011fildir \u2014 ancak kronolojik s\u0131ray\u0131 vurgulamak istedi\u011finde kullan\u0131l\u0131r.",null,null,null,null,null,null,null)
B.a7G=new A.f(B.t,"Past Perfect Anahtar Kelimeleri","**before** \u2192 \xf6nce (\xf6nceki eylem = Past Perfect)\n  \u2192 The crew had completed the checklist **before** they started the engines.\n\n**after** \u2192 sonra (\xf6nceki eylem = Past Perfect)\n  \u2192 **After** the crew **had briefed** the emergency, they executed the approach.\n\n**by the time** \u2192 ...-d\u0131\u011f\u0131nda (\xf6nceki eylem = Past Perfect)\n  \u2192 **By the time** the fire crew arrived, the aircraft **had landed** safely.\n\n**by + ge\xe7mi\u015f tarih** \u2192 ... itibar\u0131yla (eylem o zamana kadar tamamlanm\u0131\u015f)\n  \u2192 By 2010, TCAS had become mandatory on all airliners.\n\n**until / as soon as / once / while** \u2192 ba\u011fla\xe7 olarak Past Perfect tetikler",null,null,null,null,null,null,null)
B.VR=new A.r("The aircraft had already landed before the rescue team was alerted.","Kurtarma ekibine haber verilmeden \xf6nce u\xe7ak \xe7oktan inmi\u015fti.","had already landed ... before")
B.Wk=new A.r("By the time the controller noticed, the aircraft had entered the runway.","Kontrol\xf6r fark etti\u011finde u\xe7ak piste girmi\u015f bulunuyordu.","By the time ... had entered")
B.TL=new A.r("After the crew had completed the checklist, they requested pushback.","Ekip kontrol listesini tamamlad\u0131ktan sonra geri itme talebinde bulundu.","had completed")
B.Wl=new A.r("By 1970, jet travel had transformed commercial aviation.","1970'e gelindi\u011finde jet u\xe7u\u015fu ticari havac\u0131l\u0131\u011f\u0131 d\xf6n\xfc\u015ft\xfcrm\xfc\u015ft\xfc.","By 1970 ... had transformed")
