B.a59=new A.f(B.A,"\xd6rnekler",null,B.afl,null,null,null,null,null,null)
B.arv=s(["already isolated","has already isolated","had already isolated","already isolates"],t.s)
B.aGC=new A.j(-1271,B.p,0,"By the time the engineer arrived, the crew \u2026\u2026\u2026\u2026 the fault.",B.arv,2,B.m,null,null,null)
B.akA=s(["completed","had completed","have completed","completing"],t.s)
B.aBw=new A.j(-1272,B.p,0,"After the crew \u2026\u2026\u2026\u2026 the emergency checklist, they declared MAYDAY.",B.akA,1,B.n,null,null,null)
B.asv=s(["By / had flown","Until / flew","After / have flown","Before / had flown"],t.s)
B.aEd=new A.j(-1273,B.p,0,"\u2026\u2026\u2026\u2026 the time the relief crew arrived, the original crew \u2026\u2026\u2026\u2026 for 12 hours.",B.asv,0,B.n,null,null,null)
B.aiD=s(["becomes","became","had become","has become"],t.s)
B.aBH=new A.j(-1274,B.p,0,"By 2000, GPS navigation \u2026\u2026\u2026\u2026 standard on most commercial aircraft.",B.aiD,2,B.n,null,null,null)
B.alv=s([B.aGC,B.aBw,B.aEd,B.aBH],t.C)
B.a4l=new A.f(B.v,"Pratik",null,null,null,B.alv,null,null,null,null)
B.aia=s([B.aaj,B.a7G,B.a59,B.a4l],t.q)
B.jr=new A.al("std_28","Past Perfect: Anahtar Kelimeler","Past Perfect Keywords \u2014 before, after, by the time","grammar","\u23ea",B.aia,B.aB)
B.aaR=new A.f(B.w,"ADs are mandatory safety compliance documents","U\xe7u\u015fa Elveri\u015flilik Direktifi (AD), belirli bir u\xe7ak tipindeki g\xfcvenli olmayan bir durumu gidermek amac\u0131yla sivil havac\u0131l\u0131k otoritesi taraf\u0131ndan zorunlu eylem gerektiren yasal ba\u011flay\u0131c\u0131 bir belgedir. Uyumsuzluk yasad\u0131\u015f\u0131d\u0131r ve i\u015fletme sertifikas\u0131n\u0131n ask\u0131ya al\u0131nmas\u0131na yol a\xe7abilir.\n\nAD dili havac\u0131l\u0131ktaki en kesin d\xfczenleyici dildir \u2014 her kelimenin yasal a\u011f\u0131rl\u0131\u011f\u0131 vard\u0131r.",null,null,null,null,null,null,null)
B.a7z=new A.f(B.t,"\ud83d\udcdc AD Yap\u0131s\u0131",'Tipik bir AD \u015funlar\u0131 i\xe7erir:\n1. **Uygulanabilirlik** \u2014 hangi u\xe7ak/motor/par\xe7alar etkileniyor\n2. **G\xfcvensiz durum** \u2014 \xe7\xf6z\xfclecek tehlike\n3. **Gerekli eylem** \u2014 ne yap\u0131lmas\u0131 gerekiyor\n4. **Uyumluluk s\xfcresi** \u2014 ne zamana kadar yap\u0131lmal\u0131 (\xf6r. "50 u\xe7u\u015f saati i\xe7inde")\n5. **Y\xf6ntem** \u2014 nas\u0131l uyulur (servis b\xfclteni, \xf6zel prosed\xfcr)\n6. **Alternatif Uyumluluk Y\xf6ntemi (AMOC)** \u2014 onaylanm\u0131\u015f alternatif\n7. **Maliyetler** \u2014 tahmini uyumluluk maliyeti',null,null,null,null,null,null,null)
B.a8v=new A.f(B.t,"\u26a0\ufe0f Uyumluluk S\xfcresi Dili",'**"Within 50 flight hours after the effective date"** \u2014 must be done before 50 more hours\n**"At the next scheduled maintenance"** \u2014 at next A/B/C check\n**"Before further flight"** \u2014 aircraft must not fly until complied with\n**"At first opportunity"** \u2014 as soon as practical (not as urgent as "before further flight")\n**"Repetitive inspection every 200 FH"** \u2014 not a one-time action; must be repeated\n**"Terminating action"** \u2014 permanently satisfies the AD (no more repetitive checks needed)',null,null,null,null,null,null,null)
B.TY=new A.r("This AD requires repetitive inspections of the fuselage skin every 500 flight cycles.","Bu AD, her 500 u\xe7u\u015f \xe7evriminde g\xf6vde kaplamas\u0131n\u0131n tekrarl\u0131 denetimlerini gerektirmektedir.","repetitive inspections")
B.Xs=new A.r("The applicability of this AD extends to all Boeing 737-800 aircraft with serial numbers 35201 through 41234.","Bu AD'nin uygulanabilirli\u011fi, 35201 ile 41234 aras\u0131ndaki seri numaralar\u0131na sahip t\xfcm Boeing 737-800 u\xe7aklar\u0131n\u0131 kapsamaktad\u0131r.","applicability")
B.U4=new A.r("Compliance is required before further flight after the effective date.","Y\xfcr\xfcrl\xfck tarihinden sonra daha fazla u\xe7u\u015ftan \xf6nce uyum zorunludur.","before further flight")
