B.a7v=new A.f(B.al,"\u2708\ufe0f \u0130leri Okuma Stratejisi",'AD okuma anlama sorular\u0131 i\xe7in:\n\u2022 **Uygulanabilirlik** b\xf6l\xfcm\xfc hangi u\xe7aklar\u0131n etkilendi\u011fini s\xf6yler \u2014 bunu \xf6nce kontrol edin\n\u2022 "**Before further flight**" = en acil uyumluluk s\xfcresi \u2014 u\xe7ak YER\'DE KALMALIDIR\n\u2022 "**Terminating action**" = bir kez yap\u0131ld\u0131\u011f\u0131nda tekrar edici denetim gerekmez\n\u2022 **AMOC** = alternatif uyumluluk y\xf6ntemi \u2014 otorite taraf\u0131ndan onaylanmal\u0131d\u0131r\n\u2022 "**At the next scheduled**" "iste\u011fe ba\u011fl\u0131" anlam\u0131na gelmez \u2014 o noktada zorunludur\n\u2022 Tarihlere dikkat edin: "after the effective date" ile "from the date of manufacture"',null,null,null,null,null,null,null)
