B.UE=new A.r("The captain reported that the hydraulic pressure had dropped below limits.","Kaptan, hidrolik bas\u0131nc\u0131n limitin alt\u0131na d\xfc\u015ft\xfc\u011f\xfcn\xfc bildirdi.","had dropped")
B.Yw=new A.r("ATC informed the crew that the runway was temporarily closed.","ATC ekibe pistin ge\xe7ici olarak kapat\u0131ld\u0131\u011f\u0131n\u0131 bildirdi.","was temporarily closed")
