B.aad=new A.f(B.w,"Edilgenin ileri formlar\u0131","Temel edilgen yap\u0131y\u0131 biliyorsun. \u015eimdi havac\u0131l\u0131k belgelerinde s\u0131k\xe7a kar\u015f\u0131la\u015f\u0131lan **perfect passive**, **causative** (have/get something done) ve **reporting structures** (It is reported that\u2026) \xfczerine yo\u011funla\u015faca\u011f\u0131z.",null,null,null,null,null,null,null)
B.a8H=new A.f(B.t,"\u0130leri Yap\u0131lar",'**Perfect Passive:**\n\u2022 has/have been + V3 \u2192 "The engine has been inspected."\n\u2022 had been + V3 \u2192 "The part had been replaced before the flight."\n\n**Future Passive:**\n\u2022 will be + V3 \u2192 "The aircraft will be returned to service."\n\u2022 is going to be + V3 \u2192 "The runway is going to be closed."\n\n**Causative:**\n\u2022 have + object + V3 \u2192 "The airline had the engine overhauled."\n\u2022 get + object + V3 \u2192 "The crew got the fault rectified."\n\n**Reporting Passive:**\n\u2022 It is reported that\u2026 / It is believed that\u2026\n\u2022 The aircraft is reported to have deviated from the assigned route.',null,null,null,null,null,null,null)
