B.aaB=new A.f(B.w,"Dolayl\u0131 Anlat\u0131m nedir?",'Birinin s\xf6ylediklerini aktar\u0131rken do\u011frudan al\u0131nt\u0131 yapmak yerine **Reported Speech** kullan\u0131l\u0131r. Kaza raporlar\u0131nda tan\u0131k ifadeleri, ATC kay\u0131tlar\u0131n\u0131n \xf6zetleri ve bak\u0131m bildirimlerinde zorunludur:\n"The captain said that the oil pressure **had dropped** below limits."\n"ATC reported that the runway **was** contaminated."',null,null,null,null,null,null,null)
B.a5k=new A.f(B.t,"Zaman Kaymas\u0131 (Backshift)","| Do\u011frudan | Dolayl\u0131 |\n|---------|--------|\n| Present Simple | Past Simple |\n| Present Continuous | Past Continuous |\n| Past Simple | Past Perfect |\n| will | would |\n| can | could |\n| must | had to / must |\n\n**Zaman zarflar\u0131 da de\u011fi\u015fir:**\n\u2022 now \u2192 then / at that time\n\u2022 today \u2192 that day\n\u2022 yesterday \u2192 the previous day\n\u2022 tomorrow \u2192 the following day / the next day\n\u2022 here \u2192 there",null,null,null,null,null,null,null)
