B.a61=new A.f(B.w,"Havac\u0131l\u0131k bak\u0131m\u0131nda SMS","**Safety Management System (SMS)**, havac\u0131l\u0131k kurulu\u015flar\u0131n\u0131n g\xfcvenlik risklerini proaktif olarak y\xf6netmesi i\xe7in geli\u015ftirilen sistematik yakla\u015f\u0131md\u0131r. AMT'ler SMS s\xfcre\xe7lerinin aktif kat\u0131l\u0131mc\u0131lar\u0131d\u0131r.",null,null,null,null,null,null,null)
B.a3Z=new A.f(B.t,"SMS Terminolojisi",'**Temel kavramlar:**\n\u2022 Hazard \u2014 tehlike (zarar vermek i\xe7in potansiyel mevcut durum)\n\u2022 Risk \u2014 tehlikenin ger\xe7ekle\u015fme olas\u0131l\u0131\u011f\u0131 \xd7 sonucun \u015fiddeti\n\u2022 Safety occurrence \u2014 g\xfcvenlik olay\u0131\n\u2022 Near miss / close call \u2014 ramak kala (hasar olmaks\u0131z\u0131n ger\xe7ekle\u015fen olay)\n\u2022 Root cause analysis \u2014 k\xf6k neden analizi\n\u2022 Corrective action \u2014 d\xfczeltici faaliyet\n\u2022 Preventive action \u2014 \xf6nleyici faaliyet\n\u2022 Just culture \u2014 su\xe7lama yerine \xf6\u011frenmeyi hedefleyen k\xfclt\xfcr\n\u2022 Toolbox talk \u2014 bak\u0131m \xf6ncesi k\u0131sa g\xfcvenlik brifing\n\n**Hazard report ifadesi:**\n"I observed a potential hazard: [description]. Location: [X]. Risk level: [high/medium/low]. Recommended action: [X]."',null,null,null,null,null,null,null)
B.ah=new A.e9(2,"translation")
