B.a4n=new A.f(B.w,"CRM neden \xf6nemlidir?","Havac\u0131l\u0131k kazalar\u0131n\u0131n b\xfcy\xfck \xe7o\u011funlu\u011fu (yakla\u015f\u0131k %75) teknik ar\u0131za de\u011fil, **insan fakt\xf6r\xfc** kaynakl\u0131d\u0131r. CRM (Crew Resource Management) e\u011fitimi ve terminolojisi, ICAO ve EASA taraf\u0131ndan zorunlu tutulmakta; s\u0131nav sorular\u0131nda da s\u0131kl\u0131kla yer almaktad\u0131r.",null,null,null,null,null,null,null)
