B.a6t=new A.f(B.w,"Wish ve If Only ne anlama gelir?",'**Wish** ve **If only**, ger\xe7ekle\u015fmesini istedi\u011fimiz ama ger\xe7ek olmayan durumlar\u0131 ya da ge\xe7mi\u015fteki pi\u015fmanl\u0131klar\u0131 ifade eder.\n\nHavac\u0131l\u0131k kaza analizlerinde s\u0131k\xe7a kullan\u0131l\u0131r:\n"I **wish** the crew had followed the checklist."\n"**If only** the weather had been better."',null,null,null,null,null,null,null)
B.a6q=new A.f(B.t,"Yap\u0131","**\u015eimdiki ger\xe7ekd\u0131\u015f\u0131 dilek \u2192 Past Simple**\n  \u2192 I **wish** I **had** more fuel. (\u015fu an yok)\n  \u2192 **If only** the runway **were** longer. (\u015fu an de\u011fil)\n\n**Ge\xe7mi\u015fteki pi\u015fmanl\u0131k \u2192 Past Perfect**\n  \u2192 I **wish** the crew **had** noticed the warning earlier.\n  \u2192 **If only** we **hadn't taken** that route.\n\n**Gelecek de\u011fi\u015fim iste\u011fi \u2192 would + V1**\n  \u2192 I **wish** the controller **would** give us a lower altitude.\n  \u2192 I **wish** the weather **would** improve.\n\n**If only = Wish** (daha g\xfc\xe7l\xfc, dramatik anlat\u0131m)",null,null,null,null,null,null,null)
B.Wi=new A.r("I wish we had more fuel \u2014 diversion is now unavoidable.","Ke\u015fke daha fazla yak\u0131t\u0131m\u0131z olsayd\u0131 \u2014 sapma art\u0131k ka\xe7\u0131n\u0131lmaz.","wish we had")
B.Vq=new A.r("If only the crew had checked the weather before departure.","Ke\u015fke ekip kalk\u0131\u015ftan \xf6nce havay\u0131 kontrol etmi\u015f olsayd\u0131.","If only ... had checked")
B.TR=new A.r("I wish ATC would give us a direct routing \u2014 we are running low on fuel.","Ke\u015fke ATC bize do\u011frudan rota verse \u2014 yak\u0131t\u0131m\u0131z azal\u0131yor.","wish ATC would give")
B.Uv=new A.r("If only the maintenance team had caught the fault earlier.","Ke\u015fke bak\u0131m ekibi ar\u0131zay\u0131 daha erken fark etmi\u015f olsayd\u0131.","had caught ... earlier")
