B.a5P=new A.f(B.t,"Temel Prefix ve Suffix'ler","**Olumsuz yapan prefix'ler:**\n\u2022 un- \u2192 unserviceable, unsafe, unplanned\n\u2022 in-/im- \u2192 inaccurate, incomplete, impossible\n\u2022 dis- \u2192 disconnect, disembark, disallow\n\u2022 mis- \u2192 misread, miscommunicate, misidentify\n\u2022 non- \u2192 non-essential, non-standard, non-precision\n\n**\u0130sim yapan suffix'ler:**\n\u2022 -tion/-sion \u2192 navigation, inspection, revision\n\u2022 -ment \u2192 assessment, adjustment, deployment\n\u2022 -ity \u2192 visibility, stability, capability\n\u2022 -ance/-ence \u2192 clearance, turbulence, performance\n\u2022 -er/-or \u2192 controller, operator, inspector\n\n**S\u0131fat yapan suffix'ler:**\n\u2022 -able/-ible \u2192 serviceable, controllable, visible\n\u2022 -al \u2192 procedural, operational, technical\n\u2022 -ous \u2192 hazardous, numerous, continuous",null,null,null,null,null,null,null)
B.TA=new A.r("The aircraft is unserviceable and must not be flown.","U\xe7ak u\xe7u\u015fa elveri\u015fsiz ve u\xe7urulmamal\u0131d\u0131r.","unserviceable (un + service + able)")
