B.a4k=new A.f(B.w,"U\xe7u\u015f \xd6ncesi Teknik Teslim","Bak\u0131m i\u015flemi sonras\u0131nda teknisyen, u\xe7a\u011f\u0131 **certify** ederek kaptana **release** (teslim) eder. Bu s\xfcre\xe7te:\n\n\u2022 Yap\u0131lan i\u015f a\xe7\u0131k\xe7a tarif edilir\n\u2022 Herhangi bir **limitation** (k\u0131s\u0131tlama) varsa bildirilir\n\u2022 **Certificate of Release to Service (CRS)** verilir\n\nKaptan teknik g\xfcnl\xfc\u011f\xfc (technical log) imzalamadan \xf6nce sorular\u0131 sorabilir.",null,null,null,null,null,null,null)
B.fc=new A.nx(6,"dialogue")
B.QT=new A.bS(B.f4,"Good morning, Captain. I'm the certifying engineer. I need to brief you on the maintenance carried out overnight.","G\xfcnayd\u0131n Kaptan. Ben sertifika m\xfchendisiyim. Geceyi kapsayan bak\u0131m hakk\u0131nda sizi bilgilendirmem gerekiyor.",!1)
B.Rs=new A.bS(B.dH,"Good morning. What was the defect?","G\xfcnayd\u0131n. Ar\u0131za neydi?",!1)
B.R4=new A.bS(B.f4,"We had a hydraulic fluid leak on the green system, identified at the actuator on the left main gear door. We replaced the actuator seal and re-sealed the line. System was pressure-tested and certified serviceable.","Ye\u015fil sistemde hidrolik s\u0131v\u0131 ka\xe7a\u011f\u0131 vard\u0131, sol ana ini\u015f tak\u0131m\u0131 kap\u0131 akt\xfcat\xf6r\xfcnde tespit edildi. Akt\xfcat\xf6r contas\u0131n\u0131 de\u011fi\u015ftirdik ve hatt\u0131 yeniden s\u0131zd\u0131rmaz hale getirdik. Sistem bas\u0131n\xe7 testine tabi tutuldu ve hizmete uygun olarak sertifikaland\u0131r\u0131ld\u0131.",!0)
B.RC=new A.bS(B.dH,"Any limitations or deferred items?","Herhangi bir k\u0131s\u0131tlama veya ertelenen i\u015f var m\u0131?",!0)
B.Ru=new A.bS(B.f4,"No limitations. All systems are serviceable. The MEL item from yesterday \u2014 the reading light in seat 12B \u2014 has also been rectified.","K\u0131s\u0131tlama yok. T\xfcm sistemler hizmete haz\u0131r. D\xfcnden kalan MEL maddesi \u2014 12B koltu\u011fundaki okuma lambas\u0131 \u2014 da giderildi.",!1)
B.QY=new A.bS(B.dH,"Understood. What's the current hydraulic fluid level?","Anla\u015f\u0131ld\u0131. Mevcut hidrolik s\u0131v\u0131 seviyesi ne?",!1)
B.QX=new A.bS(B.f4,"Green system is full \u2014 serviced to maximum per AMM 29-10-00. Total fluid added: 1.2 litres Skydrol LD-4.","Ye\u015fil sistem dolu \u2014 AMM 29-10-00'a g\xf6re maksimum seviyeye servis yap\u0131ld\u0131. Toplam eklenen s\u0131v\u0131: 1,2 litre Skydrol LD-4.",!1)
B.Re=new A.bS(B.dH,"Good. I'm satisfied. I'll sign the tech log now.","G\xfczel. Tatmin oldum. \u015eimdi teknik g\xfcnl\xfc\u011f\xfc imzalayaca\u011f\u0131m.",!1)
B.QR=new A.bS(B.f4,"Thank you, Captain. Certificate of Release to Service is on page 4. Safe flight.","Te\u015fekk\xfcrler Kaptan. Hizmete Verme Sertifikas\u0131 4. sayfada. \u0130yi u\xe7u\u015flar.",!0)
