B.a7W=new A.f(B.w,"Her METAR unsurunun kesin bir anlam\u0131 vard\u0131r","\xc7eviri sorular\u0131 \xe7o\u011funlukla METAR veya TAF kodlar\u0131n\u0131 yorumlaman\u0131z\u0131 ve d\xfcz dille ifade etmenizi \u2014 ya da bir hava g\xf6zleminin do\u011fru T\xfcrk\xe7e \xe7evirisini belirlemenizi ister.\n\nBir METAR'in her unsuru sabit s\u0131rayla gelir ve kesin bir anlam ta\u015f\u0131r. S\u0131ray\u0131 kar\u0131\u015ft\u0131rmak veya bir k\u0131saltmay\u0131 yanl\u0131\u015f yorumlamak puan kaybettirir.",null,null,null,null,null,null,null)
B.ab9=new A.f(B.t,"\ud83c\udf26\ufe0f METAR Unsur S\u0131ras\u0131","**METAR** LTBA **120850Z** **35015KT** **9999** **FEW030** **18/08** **Q1013** **NOSIG**\n\n1. Station ICAO code: LTBA (Istanbul)\n2. Date/Time: 12th at 08:50 UTC\n3. Wind: 350\xb0/15 knots\n4. Visibility: 9999 = 10km or more\n5. Cloud: FEW at 3,000ft AGL\n6. Temp/Dewpoint: 18\xb0C / 8\xb0C\n7. QNH: 1013 hPa\n8. Trend: NOSIG = no significant change",null,null,null,null,null,null,null)
B.a3J=new A.f(B.t,"\u2601\ufe0f Bulut \xd6rt\xfcs\xfc Kodlar\u0131",'**FEW** \u2014 1\u20132 oktas (1/8\u20132/8 coverage)\n**SCT (Scattered)** \u2014 3\u20134 oktas\n**BKN (Broken)** \u2014 5\u20137 oktas\n**OVC (Overcast)** \u2014 8 oktas (full coverage)\n**NSC** \u2014 No Significant Cloud\n**NCD** \u2014 No Cloud Detected (auto station)\n\nHeight is given in hundreds of feet AGL:\n"BKN015" = broken cloud at 1,500 feet AGL\n"OVC008" = overcast at 800 feet AGL',null,null,null,null,null,null,null)
B.VB=new A.r("OVC008 means overcast cloud at 800 feet above aerodrome level.","OVC008, ta\u015f\u0131t alan\u0131 seviyesinin 800 feet \xfczerinde tam kapal\u0131 bulut anlam\u0131na gelir.","overcast")
