B.a4I=new A.f(B.w,"Acil durum terimleri neden kritiktir?","Acil durumlarda do\u011fru terminolojiyi bilmek hayat kurtar\u0131r. Pilot stres alt\u0131nda olsa bile standart ifadeler, ATC'nin an\u0131nda do\u011fru prosed\xfcr\xfc ba\u015flatmas\u0131n\u0131 sa\u011flar. ICAO, acil durum ileti\u015fimi i\xe7in net bir hiyerar\u015fi belirlemi\u015ftir.",null,null,null,null,null,null,null)
B.a75=new A.f(B.t,"\ud83c\udd98 Acil Durum Hiyerar\u015fisi",'**MAYDAY** (3 kez tekrar) \u2192 tehlike durumu (distress)\n\u2022 Can veya u\xe7ak tehlikede, acil yard\u0131m gerekiyor\n\u2022 "MAYDAY MAYDAY MAYDAY, [\xe7a\u011fr\u0131 i\u015fareti], [pozisyon], [problem], [niyet], [can say\u0131s\u0131]"\n\n**PAN-PAN** (3 kez tekrar) \u2192 aciliyet durumu (urgency)\n\u2022 Tehlike yak\u0131n de\u011fil ama acil yard\u0131m veya \xf6ncelik gerekiyor\n\u2022 Format MAYDAY ile ayn\u0131\n\n**SECURITE** (3 kez tekrar) \u2192 emniyet mesaj\u0131\n\u2022 Navigasyon tehlikesi veya \xf6nemli meteoroloji uyar\u0131s\u0131\n\n**Yayg\u0131n acil ifadeler:**\n\u2022 "Declaring emergency" \u2192 acil ilan ediyorum\n\u2022 "Minimum fuel" \u2192 minimum yak\u0131t (\xe7\u0131km\u0131yor ama \xf6ncelik ister)\n\u2022 "Fuel emergency" \u2192 yak\u0131t acil (can tehlikesi s\u0131n\u0131r\u0131)\n\u2022 "Engine failure/fire/smoke in cabin"\n\u2022 "Returning to departure airport"\n\u2022 "Request immediate landing"',null,null,null,null,null,null,null)
