B.YM=new A.r("PROB30 \u2014 30% probability of the stated conditions.","PROB30: Belirtilen ko\u015fullar\u0131n ger\xe7ekle\u015fme olas\u0131l\u0131\u011f\u0131 %30.","PROB30")
