B.a5e=new A.f(B.w,"Anormal kontrol listelerinin sabit dil kal\u0131plar\u0131 vard\u0131r","Motor ar\u0131zas\u0131 ve di\u011fer anormal/acil durum kontrol listeleri havac\u0131l\u0131ktaki en kesin dili kullan\u0131r. Bu alandan gelen bo\u015fluk doldurma sorular\u0131 hem teknik bilgiyi hem de kelime do\u011frulu\u011funu s\u0131nar.\n\nDo\u011fru prosed\xfcr fiili kritik \xf6neme sahiptir \u2014 yanl\u0131\u015f eylem kelimesi kullanmak havac\u0131l\u0131kta asla kabul edilemez.",null,null,null,null,null,null,null)
B.a9U=new A.f(B.t,"\ud83d\udd25 Motor Ar\u0131zas\u0131 Kelime Bilgisi","**Thrust lever** \u2014 controls engine power (throttle)\n**Fuel control lever** \u2014 starts/stops fuel to engine\n**Engine fire handle** \u2014 emergency shut-off and fire suppression control\n**HP fuel cock / Shutoff valve** \u2014 high-pressure fuel control\n**N1 / N2** \u2014 fan speed (%) / core speed (%)\n**EGT** \u2014 Exhaust Gas Temperature\n**ITT** \u2014 Interstage Turbine Temperature\n**Surge** \u2014 compressor stall; loud bang, rpm fluctuation",null,null,null,null,null,null,null)
B.a50=new A.f(B.t,"\ud83d\udccb Kontrol Listesi Eylem Kal\u0131plar\u0131",'Motor ar\u0131zas\u0131 kontrol listesi s\u0131ras\u0131 \u015fu kesin ifadeleri kullan\u0131r:\n\n"Engine fire, failure or severe damage \u2014 **ECAM ACTIONS**\u2026 **PERFORM**"\n"Thrust lever \u2014 **IDLE**"\n"Motor iyile\u015fmiyorsa \u2014 engine **MASTER switch** \u2014 **OFF**"\n"Engine fire pushbutton \u2014 **PUSH**"\n"Yang\u0131n s\xf6nmezse \u2014 ikinci ajan\u0131 **DISCHARGE** et"\n"En yak\u0131n uygun havaliman\u0131na in \u2014 **CONSIDER**"\n\nAnahtar kal\u0131p fiilleri: **idle, push, pull, discharge, confirm, verify, cross-check**',null,null,null,null,null,null,null)
B.Xp=new A.r("In the event of an engine fire, the crew must pull the engine fire handle.","Motor yang\u0131n\u0131 durumunda ekip, motor yang\u0131n kolunu \xe7ekmelidir.","pull the engine fire handle")
B.Yp=new A.r("If the fire is not extinguished, discharge the second fire extinguisher agent.","Yang\u0131n s\xf6nd\xfcr\xfclemezse ikinci s\xf6nd\xfcr\xfcc\xfc maddesini de\u015farj edin.","discharge")
B.YG=new A.r("Cross-check the affected engine number before taking any action.","Herhangi bir i\u015flem yapmadan \xf6nce etkilenen motor numaras\u0131n\u0131 \xe7apraz kontrol edin.","Cross-check")
