B.a92=new A.f(B.A,"Anormal Kontrol Listesi Dili",null,B.afB,null,null,null,null,null,null)
B.a6G=new A.f(B.al,"\u2708\ufe0f S\u0131nav \u0130pucu",'S\u0131nanan kontrol listesi eylem fiilleri:\n\u2022 **Pull** fire handle ("activate" veya "turn" de\u011fil \u2014 yang\u0131n kolunu **\xe7ek**)\n\u2022 **Discharge** extinguisher ("release" veya "fire" de\u011fil \u2014 s\xf6nd\xfcr\xfcc\xfcy\xfc **de\u015farj et**)\n\u2022 **Cross-check** \u2014 s\u0131navda bu ad\u0131m\u0131 asla atlama\n\u2022 **Monitor** vs. **Check**: izleme s\xfcreklidir; kontrol tek bir eylemdir\n\u2022 "Land at nearest suitable" \u2260 "hemen sapt\u0131r" \u2014 ekip "uygunlu\u011fu" de\u011ferlendirmelidir',null,null,null,null,null,null,null)
