B.aa1=new A.f(B.w,"Artikeller belirlilik ve ba\u011flam\u0131 g\xf6sterir",'Artikeller basit g\xf6r\xfcnse de, teknik belgeler, k\u0131lavuzlar ve ATC ileti\u015fimleri belirli artikel kullan\u0131m kal\u0131plar\u0131n\u0131 izledi\u011finden havac\u0131l\u0131k \u0130ngilizcesinde en s\u0131k s\u0131nanan dilbilgisi noktalar\u0131ndan biridir.\n\nYanl\u0131\u015f bir artikel anlam\u0131 de\u011fi\u015ftirir: "**a** hydraulic pump" (herhangi bir hidrolik pompa) vs. "**the** hydraulic pump" (konu\u015ftu\u011fumuz belirli bir pompa).',null,null,null,null,null,null,null)
B.Zx=new A.kW(5,"articleUsage")
B.a2V=new A.f(B.e8,"Artikel kullan\u0131m k\u0131lavuzu",null,null,B.Zx,null,null,null,null,null)
B.abv=new A.f(B.t,"Artikel Kurallar\u0131",'**"a / an"** \u2014 indefinite: first mention, one of many, job/type\n\u2192 "A hydraulic pump pressurizes the fluid."\n\u2192 "He is a licensed aircraft engineer."\n\n**"the"** \u2014 definite: previously mentioned, unique, specific system\n\u2192 "The hydraulic pump (mentioned before) failed."\n\u2192 "The captain (there is only one) made the decision."\n\n**Zero article** \u2014 general statements, uncountable nouns, proper names\n\u2192 "Aviation safety depends on training." (general)\n\u2192 "ILS runway 36L is available." (proper name)',null,null,null,null,null,null,null)
