B.Y4=new A.r("An ELT must be installed on all aircraft operating under IFR.","IFR alt\u0131nda u\xe7u\u015f yapan t\xfcm u\xe7aklarda bir ELT bulunmal\u0131d\u0131r.","An ELT")
B.Yv=new A.r("Aviation fuel must be free of contaminants before being loaded.","Havac\u0131l\u0131k yak\u0131t\u0131 y\xfcklenmeden \xf6nce kirleticilerden ar\u0131nd\u0131r\u0131lm\u0131\u015f olmal\u0131d\u0131r.","Aviation fuel")
