B.abA=new A.f(B.w,"Resmi havac\u0131l\u0131k belgelerinin \xf6zel dil kal\u0131plar\u0131 vard\u0131r","Operasyon k\u0131lavuzlar\u0131, bak\u0131m k\u0131lavuzlar\u0131 (AMM) ve u\xe7u\u015fa elveri\u015flilik direktifleri, kesin hukuki ve teknik \xe7\u0131kar\u0131mlar i\xe7eren resmi \u0130ngilizce kullan\u0131r. Bu d\xfczeydeki \xe7eviri sorular\u0131, yaln\u0131zca kelimeleri de\u011fil, arkar\u0131ndaki **d\xfczenleyici amac\u0131** da anlamay\u0131 gerektirir.",null,null,null,null,null,null,null)
B.a2H=new A.f(B.t,"\ud83d\udcd5 D\xfczenleyici Dil","**Shall** \u2014 mandatory requirement (legal obligation in ICAO documents)\n**Should** \u2014 recommended practice (not legally binding, but expected)\n**May** \u2014 permitted (optional)\n**Must** \u2014 mandatory (operational context, not formal ICAO legal text)\n\n**Compliance** \u2014 acting in accordance with a regulation\n**In accordance with (IAW)** \u2014 following specified requirements\n**Subject to** \u2014 conditional upon something\n**Notwithstanding** \u2014 despite; even though\n**Hereinafter** \u2014 from this point forward in the document",null,null,null,null,null,null,null)
