B.Ul=new A.r("At Decision Height, if the required visual reference is not established, a go-around must be executed.","Karar \u0130rtifas\u0131nda, gerekli g\xf6rsel referans sa\u011flanamazsa t\u0131rman\u0131\u015f prosed\xfcr\xfc uygulanmal\u0131d\u0131r.","Decision Height")
