B.YI=new A.r("Sleep inertia must be considered before using controlled rest during long-haul flights.","Uzun menzilli u\xe7u\u015flarda kontroll\xfc uyku kullan\u0131lmadan \xf6nce uyku ataleti g\xf6z \xf6n\xfcnde bulundurulmal\u0131d\u0131r.","Sleep inertia")
