B.aa7=new A.f(B.w,"\xc7ocuk yolcularla ileti\u015fim","Bebekli ve \xe7ocuklu yolcular \xf6zel ekipman ve g\xfcvenlik k\u0131lavuzlar\u0131na ihtiya\xe7 duyar. Kabin ekibinin bu ekipmanlara ili\u015fkin terminolojiyi ve kural ifadelerini bilmesi gerekir.",null,null,null,null,null,null,null)
