B.aaZ=new A.f(B.w,"Servis hatalar\u0131 nas\u0131l y\xf6netilir?","Kabin hizmetlerinde aksakl\u0131klar (eksik yemek se\xe7ene\u011fi, sistem ar\u0131zas\u0131, koltuk sorunu) ya\u015fanabilir. Bunlar\u0131 profesyonel bir dille y\xf6netmek, m\xfc\u015fteri memnuniyetini ve g\xfcveni korur.",null,null,null,null,null,null,null)
